import { type HTMLAttributes, forwardRef } from "react";
import { clsx } from "clsx";
import { Divider } from "../Divider";
import * as styles from "./ListItemDivider.css";

export interface ListItemDividerProps extends HTMLAttributes<HTMLLIElement> {}

/**
 * A divider for use within lists, rendered as an li element containing a Divider.
 */
export const ListItemDivider = forwardRef<HTMLLIElement, ListItemDividerProps>(
  ({ className, ...props }, ref) => {
    return (
      <li
        ref={ref}
        className={clsx(styles.listItemDivider, className)}
        role="presentation"
        {...props}
      >
        <Divider />
      </li>
    );
  }
);

ListItemDivider.displayName = "ListItemDivider";
